// KillAura / ESP target cleanup on entity destruction
if (event.getPacket() instanceof S13PacketDestroyEntities) {
  S13PacketDestroyEntities s13 =
    (S13PacketDestroyEntities) event.getPacket();
  for (int id : s13.getEntityIDs()) {
    targetList.remove(id);
    esplist.remove(id);
    antiBotList.remove(id);
  }
}
